	public void AddLogs(List<SharedAdminLog> logs)
	{
		Span<SharedAdminLog> span = CollectionsMarshal.AsSpan(logs);
		for (int i = 0; i < span.Length; i++)
		{
			ref SharedAdminLog log = ref span[i];
			HSeparator hSeparator = new HSeparator();
			AdminLogLabel adminLogLabel = new AdminLogLabel(ref log, hSeparator);
			((Control)adminLogLabel).Visible = ShouldShowLog(adminLogLabel);
			TotalLogs++;
			if (((Control)adminLogLabel).Visible)
			{
				ShownLogs++;
			}
			((Control)LogsContainer).AddChild((Control)(object)adminLogLabel);
			((Control)LogsContainer).AddChild((Control)(object)hSeparator);
		}
		UpdateCount();
	}

	public void SetLogs(List<SharedAdminLog> logs)
	{
		((Control)LogsContainer).RemoveAllChildren();
		UpdateCount(0, 0);
		AddLogs(logs);
	}

	public void UpdateCount(int? shown = null, int? total = null, int? round = null)
	{
		if (shown.HasValue)
		{
			ShownLogs = shown.Value;
